import sys

n = int(sys.stdin.readline())
a = list(map(int, sys.stdin.readline().split()))

a.reverse()
b = 0
for i in a:
    if i == 25:
        b += 1
    elif i == 50:
        b -= 1
        if b < 0:
            print('NO')
            break
    elif i == 100:
        b -= 2
